class DocumentLoader:
    """Loads and chunks documents from various sources."""

    SUPPORTED_EXTENSIONS = {".txt", ".md", ".json", ".csv", ".py", ".html", ".pdf"}

    def __init__(self, chunk_size: int = 500, chunk_overlap: int = 100):
        self.chunk_size = chunk_size
        self.chunk_overlap = chunk_overlap

    def load_file(self, file_path: str) -> List[Dict]:
        """Load a single file and return list of document dicts."""
        path = Path(file_path)
        if not path.exists():
            print(f"Warning: File not found: {file_path}")
            return []

        ext = path.suffix.lower()
        if ext not in self.SUPPORTED_EXTENSIONS:
            print(f"Warning: Unsupported file type: {ext}")
            return []

        try:
            if ext == ".json":
                return self._load_json(path)
            elif ext == ".csv":
                return self._load_csv(path)
            elif ext == ".pdf":
                return self._load_pdf(path)
            else:
                return self._load_text(path)
        except Exception as e:
            print(f"Error loading {file_path}: {e}")
            return []

    def _load_text(self, path: Path) -> List[Dict]:
        """Load a text-based file."""
        with open(path, "r", encoding="utf-8", errors="ignore") as f:
            content = f.read()
        return self._create_chunks(content, str(path))

    def _load_json(self, path: Path) -> List[Dict]:
        """Load a JSON file."""
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)

        if isinstance(data, list):
            documents = []
            for i, item in enumerate(data):
                if isinstance(item, dict):
                    content = "\n".join(f"{k}: {v}" for k, v in item.items())
                else:
                    content = str(item)
                documents.extend(self._create_chunks(content, f"{path}[{i}]"))
            return documents
        elif isinstance(data, dict):
            content = json.dumps(data, indent=2)
            return self._create_chunks(content, str(path))
        else:
            return self._create_chunks(str(data), str(path))

    def _load_csv(self, path: Path) -> List[Dict]:
        """Load a CSV file."""
        import csv
        documents = []
        with open(path, "r", encoding="utf-8", errors="ignore") as f:
            reader = csv.DictReader(f)
            for i, row in enumerate(reader):
                content = "\n".join(f"{k}: {v}" for k, v in row.items() if v)
                documents.extend(self._create_chunks(content, f"{path}[row_{i}]"))
        return documents

    def _load_pdf(self, path: Path) -> List[Dict]:
        """Load a PDF file (requires PyPDF2)."""
        try:
            import PyPDF2
        except ImportError:
            os.system("pip install PyPDF2")
            import PyPDF2

        documents = []
        with open(path, "rb") as f:
            reader = PyPDF2.PdfReader(f)
            for page_num, page in enumerate(reader.pages):
                text = page.extract_text()
                if text.strip():
                    chunks = self._create_chunks(
                        text, f"{path}[page_{page_num + 1}]"
                    )
                    documents.extend(chunks)
        return documents

    def _create_chunks(self, text: str, source: str) -> List[Dict]:
        """Split text into overlapping chunks."""
        text = text.strip()
        if not text:
            return []

        # Split into sentences first for cleaner chunks
        sentences = self._split_into_sentences(text)
        chunks = []
        current_chunk = []
        current_length = 0

        for sentence in sentences:
            sentence_length = len(sentence)

            if current_length + sentence_length > self.chunk_size and current_chunk:
                chunk_text = " ".join(current_chunk)
                chunk_id = hashlib.md5(
                    f"{source}:{chunk_text[:100]}".encode()
                ).hexdigest()

                chunks.append({
                    "id": chunk_id,
                    "text": chunk_text,
                    "source": source,
                    "chunk_index": len(chunks),
                })

                # Keep overlap
                overlap_length = 0
                overlap_sentences = []
                for s in reversed(current_chunk):
                    if overlap_length + len(s) <= self.chunk_overlap:
                        overlap_sentences.insert(0, s)
                        overlap_length += len(s)
                    else:
                        break

                current_chunk = overlap_sentences
                current_length = overlap_length

            current_chunk.append(sentence)
            current_length += sentence_length

        # Don't forget the last chunk
        if current_chunk:
            chunk_text = " ".join(current_chunk)
            chunk_id = hashlib.md5(
                f"{source}:{chunk_text[:100]}".encode()
            ).hexdigest()
            chunks.append({
                "id": chunk_id,
                "text": chunk_text,
                "source": source,
                "chunk_index": len(chunks),
            })

        return chunks

    def _split_into_sentences(self, text: str) -> List[str]:
        """Simple sentence splitting."""
        import re
        # Split on sentence boundaries
        sentences = re.split(r'(?<=[.!?])\s+', text)
        # Further split very long sentences
        result = []
        for sentence in sentences:
            if len(sentence) > self.chunk_size:
                # Split on newlines or other boundaries
                parts = re.split(r'\n+', sentence)
                for part in parts:
                    if len(part) > self.chunk_size:
                        # Force split at chunk_size
                        words = part.split()
                        current = []
                        length = 0
                        for word in words:
                            if length + len(word) + 1 > self.chunk_size and current:
                                result.append(" ".join(current))
                                current = []
                                length = 0
                            current.append(word)
                            length += len(word) + 1
                        if current:
                            result.append(" ".join(current))
                    elif part.strip():
                        result.append(part.strip())
            elif sentence.strip():
                result.append(sentence.strip())
        return result

    def load_directory(self, directory_path: str, recursive: bool = True) -> List[Dict]:
        """Load all supported files from a directory."""
        path = Path(directory_path)
        if not path.exists():
            print(f"Warning: Directory not found: {directory_path}")
            return []

        documents = []
        pattern = "**/*" if recursive else "*"

        for file_path in path.glob(pattern):
            if file_path.is_file() and file_path.suffix.lower() in self.SUPPORTED_EXTENSIONS:
                print(f"Loading: {file_path}")
                docs = self.load_file(str(file_path))
                documents.extend(docs)
                print(f"  -> {len(docs)} chunks")

        print(f"\nTotal documents loaded: {len(documents)} chunks")
        return documents


class EmbeddingEngine:
    """Handles text embedding using sentence-transformers or OpenAI."""

    def __init__(self, model_name: str = "all-MiniLM-L6-v2", use_openai: bool = False):
        self.use_openai = use_openai
        self.model_name = model_name

        if use_openai:
            api_key = os.getenv("OPENAI_API_KEY")
            if not api_key:
                raise ValueError("OPENAI_API_KEY environment variable required for OpenAI embeddings")
            self.client = openai.OpenAI(api_key=api_key)
            self.embedding_model = "text-embedding-3-small"
        else:
            print(f"Loading embedding model: {model_name}")
            self.model = SentenceTransformer(model_name)
            print("Embedding model loaded.")

    def embed(self, texts: List[str]) -> List[List[float]]:
        """Generate embeddings for a list of texts."""
        if self.use_openai:
            return self._embed_openai(texts)
        else:
            return self._embed_local(texts)

    def _embed_local(self, texts: List[str]) -> List[List[float]]:
        """Embed using local sentence-transformers model."""
        embeddings = self.model.encode(texts, show_progress_bar=len(texts) > 10)
        return embeddings.tolist()

    def _embed_openai(self, texts: List[str]) -> List[List[float]]:
        """Embed using OpenAI API."""
        batch_size = 100
        all_embeddings = []

        for i in range(0, len(texts), batch_size):
            batch = texts[i:i + batch_size]
            response = self.client.embeddings.create(
                input=batch,
                model=self.embedding_model,
            )
            batch_embeddings = [item.embedding for item in response.data]
            all_embeddings.extend(batch_embeddings)

        return all_embeddings


class VectorStore:
    """ChromaDB-based vector store for document storage and retrieval."""

    def __init__(
        self,
        collection_name: str = "company_knowledge_base",
        persist_directory: str = "./chroma_db",
        embedding_engine: Optional[EmbeddingEngine] = None,
    ):
        self.collection_name = collection_name
        self.persist_directory = persist_directory
        self.embedding_engine = embedding_engine or EmbeddingEngine()

        # Initialize ChromaDB
        self.chroma_client = chromadb.PersistentClient(path=persist_directory)

        # Get or create collection
        self.collection = self.chroma_client.get_or_create_collection(
            name=collection_name,
            metadata={"description": "Company internal knowledge base"},
        )

        print(f"Vector store initialized. Collection '{collection_name}' has {self.collection.count()} documents.")

    def add_documents(self, documents: List[Dict], batch_size: int = 50):
        """Add documents to the vector store."""
        if not documents:
            print("No documents to add.")
            return

        total = len(documents)
        print(f"Adding {total} documents to vector store...")

        for i in range(0, total, batch_size):
            batch = documents[i:i + batch_size]

            ids = [doc["id"] for doc in batch]
            texts = [doc["text"] for doc in batch]
            metadatas = [
                {
                    "source": doc.get("source", "unknown"),
                    "chunk_index": doc.get("chunk_index", 0),
                }
                for doc in batch
            ]

            # Generate embeddings
            embeddings = self.embedding_engine.embed(texts)

            # Upsert to ChromaDB
            self.collection.upsert(
                ids=ids,
                embeddings=embeddings,
                documents=texts,
                metadatas=metadatas,
            )

            progress = min(i + batch_size, total)
            print(f"  Progress: {progress}/{total} documents added")

        print(f"Done. Collection now has {self.collection.count()} documents.")

    def search(self, query: str, top_k: int = 5) -> List[Dict]:
        """Search for relevant documents given a query."""
        if self.collection.count() == 0:
            return []

        # Generate query embedding
        query_embedding = self.embedding_engine.embed([query])[0]

        # Query ChromaDB
        results = self.collection.query(
            query_embeddings=[query_embedding],
            n_results=min(top_k, self.collection.count()),
            include=["documents", "metadatas", "distances"],
        )

        # Format results
        documents = []
        if results and results["documents"]:
            for i in range(len(results["documents"][0])):
                doc = {
                    "text": results["documents"][0][i],
                    "source": results["metadatas"][0][i].get("source", "unknown"),
                    "chunk_index": results["metadatas"][0][i].get("chunk_index", 0),
                    "distance": results["distances"][0][i],
                    "relevance_score": 1 - results["distances"][0][i],  # Convert distance to similarity
                }
                documents.append(doc)

        return documents

    def clear(self):
        """Clear all documents from the collection."""
        self.chroma_client.delete_collection(self.collection_name)
        self.collection = self.chroma_client.get_or_create_collection(
            name=self.collection_name,
            metadata={"description": "Company internal knowledge base"},
        )
        print("Vector store cleared.")

    def get_stats(self) -> Dict:
        """Get statistics about the vector store."""
        count = self.collection.count()
        return {
            "collection_name": self.collection_name,
            "document_count": count,
            "persist_directory": self.persist_directory,
        }


class LLMEngine:
    """Handles LLM interactions for generating responses."""

    def __init__(
        self,
        provider: str = "openai",
        model: str = "gpt-3.5-turbo",
        api_key: Optional[str] = None,
        base_url: Optional[str] = None,
        temperature: float = 0.3,
        max_tokens: int = 1500,
    ):
        self.provider = provider
        self.model = model
        self.temperature = temperature
        self.max_tokens = max_tokens

        if provider == "openai":
            key = api_key or os.getenv("OPENAI_API_KEY")
            if not key:
                raise ValueError(
                    "OpenAI API key required. Set OPENAI_API_KEY env variable or pass api_key parameter."
                )
            kwargs = {"api_key": key}
            if base_url:
                kwargs["base_url"] = base_url
            self.client = openai.OpenAI(**kwargs)
        else:
            raise ValueError(f"Unsupported LLM provider: {provider}")

    def generate(
        self,
        query: str,
        context_documents: List[Dict],
        system_prompt: Optional[str] = None,
        conversation_history: Optional[List[Dict]] = None,
    ) -> Dict:
        """Generate a response using the LLM with retrieved context."""

        if system_prompt is None:
            system_prompt = self._default_system_prompt()

        # Build context string from all retrieved documents
        context_str = self._format_context(context_documents)

        # Build the user message with context
        user_message = self._build_prompt(query, context_str)

        # Build messages array
        messages = [{"role": "system", "content": system_prompt}]

        # Add conversation history if provided
        if conversation_history:
            for msg in conversation_history[-10:]:  # Keep last 10 messages
                messages.append(msg)

        messages.append({"role": "user", "content": user_message})

        try:
            response = self.client.chat.completions.create(
                model=self.model,
                messages=messages,
                temperature=self.temperature,
                max_tokens=self.max_tokens,
            )

            answer = response.choices[0].message.content
            usage = {
                "prompt_tokens": response.usage.prompt_tokens,
                "completion_tokens": response.usage.completion_tokens,
                "total_tokens": response.usage.total_tokens,
            }

            return {
                "answer": answer,
                "usage": usage,
                "model": self.model,
                "context_documents_used": len(context_documents),
            }

        except Exception as e:
            return {
                "answer": f"Error generating response: {str(e)}",
                "usage": {},
                "model": self.model,
                "context_documents_used": len(context_documents),
                "error": str(e),
            }

    def _default_system_prompt(self) -> str:
        return """You are an intelligent internal knowledge base assistant for our company. Your role is to help employees find accurate information from company documents.

Guidelines:
1. Answer questions based ONLY on the provided context documents.
2. If the context doesn't contain enough information to fully answer the question, clearly state what you found and what information is missing.
3. Always cite the source documents when providing information.
4. Be precise, professional, and helpful.
5. If you're not sure about something, say so rather than guessing.
6. Format your responses clearly with bullet points or numbered lists when appropriate.
7. If multiple documents contain relevant but potentially conflicting information, mention all perspectives."""

    def _format_context(self, documents: List[Dict]) -> str:
        """Format retrieved documents into a context string."""
        if not documents:
            return "No relevant documents found."

        context_parts = []
        for i, doc in enumerate(documents, 1):
            source = doc.get("source", "Unknown source")
            relevance = doc.get("relevance_score", 0)
            text = doc.get("text", "")

            context_parts.append(
                f"--- Document {i} ---\n"
                f"Source: {source}\n"
                f"Relevance Score: {relevance:.2f}\n"
                f"Content:\n{text}\n"
            )

        return "\n".join(context_parts)

    def _build_prompt(self, query: str, context: str) -> str:
        """Build the complete prompt with query and context."""
        return f"""Based on the following context documents from our internal knowledge base, please answer the user's question.

=== CONTEXT DOCUMENTS ===
{context}
=== END OF CONTEXT ===

User Question: {query}

Please provide a comprehensive answer based on the context above. Cite the relevant document sources in your response."""


class RAGChatbot:
    """Main RAG chatbot class that ties everything together."""

    def __init__(
        self,
        collection_name: str = "company_knowledge_base",
        persist_directory: str = "./chroma_db",
        embedding_model: str = "all-MiniLM-L6-v2",
        use_openai_embeddings: bool = False,
        llm_provider: str = "openai",
        llm_model: str = "gpt-3.5-turbo",
        llm_api_key: Optional[str] = None,
        llm_base_url: Optional[str] = None,
        chunk_size: int = 500,
        chunk_overlap: int = 100,
        top_k: int = 5,
        temperature: float = 0.3,
    ):
        self.top_k = top_k
        self.conversation_history: List[Dict] = []

        # Initialize components
        print("=" * 60)
        print("Initializing RAG Knowledge Base Chatbot")
        print("=" * 60)

        print("\n[1/4] Setting up document loader...")
        self.document_loader = DocumentLoader(
            chunk_size=chunk_size,
            chunk_overlap=chunk_overlap,
        )

        print("[2/4] Setting up embedding engine...")
        self.embedding_engine = EmbeddingEngine(
            model_name=embedding_model,
            use_openai=use_openai_embeddings,
        )

        print("[3/4] Setting up vector store...")
        self.vector_store = VectorStore(
            collection_name=collection_name,
            persist_directory=persist_directory,
            embedding_engine=self.embedding_engine,
        )

        print("[4/4] Setting up LLM engine...")
        self.llm_engine = LLMEngine(
            provider=llm_provider,
            model=llm_model,
            api_key=llm_api_key,
            base_url=llm_base_url,
            temperature=temperature,
        )

        print("\n" + "=" * 60)
        print("RAG Chatbot initialized successfully!")
        print("=" * 60 + "\n")

    def ingest_file(self, file_path: str):
        """Ingest a single file into the knowledge base."""
        documents = self.document_loader.load_file(file_path)
        if documents:
            self.vector_store.add_documents(documents)
        return len(documents)

    def ingest_directory(self, directory_path: str, recursive: bool = True):
        """Ingest all files from a directory into the knowledge base."""
        documents = self.document_loader.load_directory(directory_path, recursive)
        if documents:
            self.vector_store.add_documents(documents)
        return len(documents)

    def ingest_text(self, text: str, source: str = "direct_input"):
        """Ingest raw text into the knowledge base."""
        documents = self.document_loader._create_chunks(text, source)
        if documents:
            self.vector_store.add_documents(documents)
        return len(documents)

    def query(
        self,
        question: str,
        top_k: Optional[int] = None,
        include_history: bool = True,
        system_prompt: Optional[str] = None,
    ) -> Dict:
        """Query the knowledge base and generate a response."""
        k = top_k or self.top_k

        # Step 1: Retrieve relevant documents
        retrieved_docs = self.vector_store.search(question, top_k=k)

        # Step 2: Generate response with LLM
        history = self.conversation_history if include_history else None
        result = self.llm_engine.generate(
            query=question,
            context_documents=retrieved_docs,
            system_prompt=system_prompt,
            conversation_history=history,
        )

        # Step 3: Update conversation history
        self.conversation_history.append({"role": "user", "content": question})
        self.conversation_history.append(
            {"role": "assistant", "content": result["answer"]}
        )

        # Step 4: Build complete response
        result["retrieved_documents"] = [
            {
                "source": doc["source"],
                "relevance_score": doc.get("relevance_score", 0),
                "text_preview": doc["text"][:200] + "..." if len(doc["text"]) > 200 else doc["text"],
            }
            for doc in retrieved_docs
        ]
        result["question"] = question

        return result

    def clear_history(self):
        """Clear conversation history."""
        self.conversation_history = []
        print("Conversation history cleared.")

    def clear_knowledge_base(self):
        """Clear the entire knowledge base."""
        self.vector_store.clear()
        print("Knowledge base cleared.")

    def get_stats(self) -> Dict:
        """Get system statistics."""
        vs_stats = self.vector_store.get_stats()
        return {
            **vs_stats,
            "conversation_history_length": len(self.conversation_history),
            "top_k": self.top_k,
        }

    def interactive_chat(self):
        """Start an interactive chat session."""
        print("\n" + "=" * 60)
        print("  Internal Knowledge Base Chatbot")
        print("  Type 'quit' to exit, 'clear' to reset history")
        print("  Type 'stats' to see system statistics")
        print("  Type 'ingest <path>' to add documents")
        print("=" * 60 + "\n")

        while True:
            try:
                user_input = input("\n📝 You: ").strip()

                if not user_input:
                    continue

                if user_input.lower() == "quit":
                    print("\nGoodbye! 👋")
                    break

                if user_input.lower() == "clear":
                    self.clear_history()
                    continue

                if user_input.lower() == "stats":
                    stats = self.get_stats()
                    print("\n📊 System Statistics:")
                    for key, value in stats.items():
                        print(f"  {key}: {value}")
                    continue

                if user_input.lower().startswith("ingest "):
                    path = user_input[7:].strip()
                    if os.path.isdir(path):
                        count = self.ingest_directory(path)
                    elif os.path.isfile(path):
                        count = self.ingest_file(path)
                    else:
                        print(f"Path not found: {path}")
                        continue
                    print(f"✅ Ingested {count} document chunks.")
                    continue

                # Process the query
                print("\n🔍 Searching knowledge base...")
                result = self.query(user_input)

                # Display retrieved sources
                if result.get("retrieved_documents"):
                    print("\n📚 Sources found:")
                    for i, doc in enumerate(result["retrieved_documents"], 1):
                        score = doc["relevance_score"]
                        source = doc["source"]
                        print(f"  [{i}] {source} (relevance: {score:.2f})")

                # Display answer
                print(f"\n🤖 Assistant: {result['answer']}")

                # Display usage if available
                if result.get("usage"):
                    tokens = result["usage"].get("total_tokens", "N/A")
                    print(f"\n  💰 Tokens used: {tokens}")

            except KeyboardInterrupt:
                print("\n\nGoodbye! 👋")
                break
            except Exception as e:
                print(f"\n❌ Error: {e}")


