def main():
    """Main entry point demonstrating the RAG chatbot."""

    # Check for OpenAI API key
    api_key = os.getenv("OPENAI_API_KEY")

    if not api_key:
        print("⚠️  OPENAI_API_KEY not found in environment variables.")
        print("Please set it to use the LLM features:")
        print("  export OPENAI_API_KEY='your-api-key-here'")
        print()
        print("You can still test document ingestion and retrieval.")
        print()

    # Create sample documents
    print("Creating sample company documents...")
    docs_dir = create_sample_documents()
    print()

    # Initialize the chatbot
    chatbot = RAGChatbot(
        collection_name="acme_knowledge_base",
        persist_directory="./chroma_db",
        embedding_model="all-MiniLM-L6-v2",
        use_openai_embeddings=False,  # Use local embeddings
        llm_model="gpt-3.5-turbo",
        chunk_size=500,
        chunk_overlap=100,
        top_k=5,
        temperature=0.3,
    )

    # Ingest sample documents
    print("\n📂 Ingesting sample documents...")
    num_chunks = chatbot.ingest_directory(docs_dir)
    print(f"\n✅ Ingested {num_chunks} document chunks into the knowledge base.\n")

    # Print stats
    stats = chatbot.get_stats()
    print("📊 Knowledge Base Stats:")
    for key, value in stats.items():
        print(f"  {key}: {value}")

    if not api_key:
        # Demo mode without LLM - just show retrieval
        print("\n" + "=" * 60)
        print("  DEMO MODE (No LLM - Retrieval Only)")
        print("=" * 60)

        sample_queries = [
            "What are the PTO policies?",
            "How does the deployment process work?",
            "What benefits does the company offer?",
            "Tell me about the onboarding process",
            "What is the tech stack?",
        ]

        for query in sample_queries:
            print(f"\n📝 Query: {query}")
            results = chatbot.vector_store.search(query, top_k=3)
            print(f"🔍 Found {len(results)} relevant documents:")
            for i, doc in enumerate(results, 1):
                print(f"\n  [{i}] Source: {doc['source']}")
                print(f"      Relevance: {doc.get('relevance_score', 0):.2f}")
                preview = doc['text'][:150].replace('\n', ' ')
                print(f"      Preview: {preview}...")

    else:
        # Full demo with LLM
        print("\n" + "=" * 60)
        print("  Running sample queries...")
        print("=" * 60)

        sample_queries = [
            "What is our PTO policy? How many days do I get after 3 years?",
            "What's the code review process and what tools do we use?",
            "What should I do on my first day as a new employee?",
        ]

        for query in sample_queries:
            print(f"\n{'=' * 50}")
            print(f"📝 Query: {query}")
            print("-" * 50)

            result = chatbot.query(query)

            print(f"\n📚 Sources ({result['context_documents_used']} documents):")
            for doc in result.get("retrieved_documents", []):
                print(f"  • {doc['source']} (relevance: {doc['relevance_score']:.2f})")

            print(f"\n🤖 Answer:\n{result['answer']}")

            if result.get("usage"):
                print(f"\n💰 Tokens: {result['usage'].get('total_tokens', 'N/A')}")

        # Start interactive chat
        print("\n\nStarting interactive chat mode...\n")
        chatbot.clear_history()
        chatbot.interactive_chat()


if __name__ == "__main__":
    main()